import { DEFAULT_FILTERS } from '../utils/finance';
import './FilterPanel.css';

const CATEGORIES = ['savings', 'investment', 'insurance', 'crypto'];
const RISK_LEVELS = ['low', 'medium', 'high'];

export default function FilterPanel({ filters, onFilterChange, productCount, totalCount }) {
  function toggleMulti(key, value) {
    const arr = filters[key];
    const updated = arr.includes(value) ? arr.filter(v => v !== value) : [...arr, value];
    onFilterChange({ ...filters, [key]: updated });
  }

  function handleSingle(key, value) {
    onFilterChange({ ...filters, [key]: value });
  }

  function resetFilters() {
    onFilterChange(DEFAULT_FILTERS);
  }

  const hasActiveFilters =
    filters.riskLevels.length > 0 ||
    filters.categories.length > 0 ||
    filters.liquidity !== 'all' ||
    filters.timeHorizon !== 'all' ||
    filters.minReturn > 0 ||
    filters.maxReturn < 30 ||
    filters.maxMinInvestment > 0;

  return (
    <aside className="filter-panel">
      <div className="fp-header">
        <h3 className="fp-title">Filters</h3>
        <div className="fp-count">
          <span className="fp-count-num">{productCount}</span>
          <span className="fp-count-label">/ {totalCount} products</span>
        </div>
        {hasActiveFilters && (
          <button className="fp-reset btn btn-sm" onClick={resetFilters}>Reset</button>
        )}
      </div>

      {/* Risk Level */}
      <div className="fp-section">
        <p className="fp-section-title">Risk Level</p>
        <div className="fp-chips">
          {RISK_LEVELS.map(r => (
            <button
              key={r}
              className={`fp-chip fp-chip-${r} ${filters.riskLevels.includes(r) ? 'active' : ''}`}
              onClick={() => toggleMulti('riskLevels', r)}
            >
              {r === 'low' ? 'Low' : r === 'medium' ? 'Medium' : 'High'}
            </button>
          ))}
        </div>
      </div>

      {/* Category */}
      <div className="fp-section">
        <p className="fp-section-title">Category</p>
        <div className="fp-chips">
          {CATEGORIES.map(c => (
            <button
              key={c}
              className={`fp-chip ${filters.categories.includes(c) ? 'active' : ''}`}
              onClick={() => toggleMulti('categories', c)}
            >
              {c.charAt(0).toUpperCase() + c.slice(1)}
            </button>
          ))}
        </div>
      </div>

      {/* Return Range */}
      <div className="fp-section">
        <p className="fp-section-title">Return Range (%)</p>
        <div className="fp-range-row">
          <div className="form-group" style={{ flex: 1 }}>
            <label className="form-label">Min</label>
            <input
              type="number" className="form-input" min={0} max={30}
              value={filters.minReturn}
              onChange={e => handleSingle('minReturn', Number(e.target.value))}
            />
          </div>
          <span className="fp-range-sep">–</span>
          <div className="form-group" style={{ flex: 1 }}>
            <label className="form-label">Max</label>
            <input
              type="number" className="form-input" min={0} max={30}
              value={filters.maxReturn}
              onChange={e => handleSingle('maxReturn', Number(e.target.value))}
            />
          </div>
        </div>
      </div>

      {/* Liquidity */}
      <div className="fp-section">
        <p className="fp-section-title">Liquidity</p>
        <select
          className="form-select"
          value={filters.liquidity}
          onChange={e => handleSingle('liquidity', e.target.value)}
        >
          <option value="all">All</option>
          <option value="easy">Easy (Liquid)</option>
          <option value="moderate">Moderate</option>
          <option value="locked">Locked</option>
        </select>
      </div>

      {/* Time Horizon */}
      <div className="fp-section">
        <p className="fp-section-title">Time Horizon</p>
        <select
          className="form-select"
          value={filters.timeHorizon}
          onChange={e => handleSingle('timeHorizon', e.target.value)}
        >
          <option value="all">All</option>
          <option value="short">Short Term (1–2y)</option>
          <option value="medium">Medium Term (3–5y)</option>
          <option value="long">Long Term (5y+)</option>
        </select>
      </div>

      {/* Max Min Investment */}
      <div className="fp-section">
        <p className="fp-section-title">Max Min. Investment (PKR)</p>
        <input
          type="number" className="form-input" min={0} step={1000}
          placeholder="e.g. 50000"
          value={filters.maxMinInvestment || ''}
          onChange={e => handleSingle('maxMinInvestment', Number(e.target.value))}
        />
        <p style={{ fontSize: 11, color: 'var(--clr-text-muted)', marginTop: 4 }}>
          Leave blank to show all
        </p>
      </div>
    </aside>
  );
}
